mapper.select:
SELECT sf.`id`, sf.`attachment_id`, sf.`file_path`, sf.`file_size`, sf.`file_type`, sf.`org_id`, sf.`create_at`, sf.`create_by`, sf.`update_at`, sf.`update_by`, sf.`object_version_number`, sac.leaf_code, sac.category_name, sac.allowed_file_type, sa.attach_name as fileName, sa.business_id, sa.business_type FROM sys_attach_category sac JOIN sys_attachment sa ON sac.id = sa.category_id JOIN sys_file sf ON sa.id = sf.attachment_id
AND sac.id = #{params.attachCategoryId}
AND sac.leaf_code = #{params.leafCode}
AND sa.business_id = #{params.businessId}
AND sa.attach_name LIKE #{fileNameLike}
AND sa.business_type = #{params.businessType}
ORDER BY create_at DESC
